     1→import { useState, useCallback, useEffect } from "react";
     2→import { Layout } from "@/components/layout";
     3→import { useDropzone } from "react-dropzone";
     4→import { UploadCloud, FileImage, Settings2, Sparkles, Download, Save, Loader2, X } from "lucide-react";
     5→import { fileToBase64, createThumbnail, cn } from "@/lib/utils";
     6→import { useGetSettings, useGenerateCaptions, useRefineCaption, useRewriteCaption, useSaveHistory } from "@workspace/api-client-react";
     7→import { CaptionCard } from "@/components/caption-card";
     8→import { PlatformIcon } from "@/components/platform-icon";
     9→import { Button } from "@/components/ui/button";
    10→import { useToast } from "@/hooks/use-toast";
    11→import { motion, AnimatePresence } from "framer-motion";
    12→
    13→export default function Generator() {
    14→  const { data: globalSettings } = useGetSettings();
    15→  const generateMutation = useGenerateCaptions();
    16→  const refineMutation = useRefineCaption();
    17→  const rewriteMutation = useRewriteCaption();
    18→  const saveHistoryMutation = useSaveHistory();
    19→  const { toast } = useToast();
    20→
    21→  // Upload State
    22→  const [file, setFile] = useState<File | null>(null);
    23→  const [preview, setPreview] = useState<string | null>(null);
    24→  const [base64Data, setBase64Data] = useState<string | null>(null);
    25→  
    26→  // Input State
    27→  const [mapType, setMapType] = useState<"geopolitical" | "historical" | "data-infographic" | "other">("geopolitical");
    28→  const [contextNotes, setContextNotes] = useState("");
    29→  
    30→  // Overrides State
    31→  const [overrides, setOverrides] = useState<Record<string, any>>({});
    32→  const [showOverrides, setShowOverrides] = useState(false);
    33→  
    34→  // Results State
    35→  const [results, setResults] = useState<Record<string, string> | null>(null);
    36→  const [processingPlatforms, setProcessingPlatforms] = useState<Record<string, boolean>>({});
    37→
    38→  useEffect(() => {
    39→    if (globalSettings && Object.keys(overrides).length === 0) {
    40→      resetOverrides();
    41→    }
    42→  }, [globalSettings]);
    43→
    44→  const resetOverrides = () => {
    45→    if (!globalSettings) return;
    46→    const mapped: Record<string, any> = {};
    47→    globalSettings.forEach(s => {
    48→      mapped[s.platformId] = {
    49→        instructions: s.instructions,
    50→        audience: s.audience
    51→      };
    52→    });
    53→    setOverrides(mapped);
    54→  };
    55→
    56→  const onDrop = useCallback(async (acceptedFiles: File[]) => {
    57→    const selected = acceptedFiles[0];
    58→    if (selected) {
    59→      setFile(selected);
    60→      setPreview(URL.createObjectURL(selected));
    61→      try {
    62→        const b64 = await fileToBase64(selected);
    63→        setBase64Data(b64);
    64→      } catch (e) {
    65→        toast({ variant: "destructive", title: "Error", description: "Failed to process image." });
    66→      }
    67→    }
    68→  }, [toast]);
    69→
    70→  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    71→    onDrop,
    72→    accept: { 'image/jpeg': [], 'image/png': [], 'image/webp': [] },
    73→    maxFiles: 1
    74→  });
    75→
    76→  const handleGenerate = async () => {
    77→    if (!base64Data || !file) return;
    78→    
    79→    setResults(null);
    80→    try {
    81→      const data = await generateMutation.mutateAsync({
    82→        data: {
    83→          imageData: base64Data,
    84→          imageMediaType: file.type,
    85→          mapType: mapType,
    86→          contextNotes: contextNotes || null,
    87→          platformOverrides: overrides as any
    88→        }
    89→      });
    90→      setResults(data as any);
    91→      toast({ title: "Analysis Complete", description: "Captions generated successfully." });
    92→    } catch (e) {
    93→      toast({ variant: "destructive", title: "Generation Failed", description: "Could not generate captions. Please try again." });
    94→    }
    95→  };
    96→
    97→  const handleCaptionUpdate = (platform: string, text: string) => {
    98→    if (results) {
    99→      setResults({ ...results, [platform]: text });
   100→    }
   101→  };
   102→
   103→  const handleRefine = async (platform: string, instruction: string) => {
   104→    if (!results) return;
   105→    setProcessingPlatforms(p => ({ ...p, [platform]: true }));
   106→    try {
   107→      const res = await refineMutation.mutateAsync({
   108→        data: {
   109→          platform,
   110→          currentCaption: results[platform],
   111→          instruction
   112→        }
   113→      });
   114→      handleCaptionUpdate(platform, res.caption);
   115→    } catch (e) {
   116→      toast({ variant: "destructive", title: "Refinement Failed", description: "Error refining caption." });
   117→    } finally {
   118→      setProcessingPlatforms(p => ({ ...p, [platform]: false }));
   119→    }
   120→  };
   121→
   122→  const handleRewrite = async (platform: string) => {
   123→    if (!base64Data || !file || !results) return;
   124→    setProcessingPlatforms(p => ({ ...p, [platform]: true }));
   125→    try {
   126→      const res = await rewriteMutation.mutateAsync({
   127→        data: {
   128→          imageData: base64Data,
   129→          imageMediaType: file.type,
   130→          platform,
   131→          mapType,
   132→          contextNotes: contextNotes || null,
   133→          instructions: overrides[platform]?.instructions || "",
   134→          audience: overrides[platform]?.audience || ""
   135→        }
   136→      });
   137→      handleCaptionUpdate(platform, res.caption);
   138→    } catch (e) {
   139→      toast({ variant: "destructive", title: "Rewrite Failed", description: "Error rewriting caption." });
   140→    } finally {
   141→      setProcessingPlatforms(p => ({ ...p, [platform]: false }));
   142→    }
   143→  };
   144→
   145→  const handleDownloadAll = () => {
