     1→import { createHmac, timingSafeEqual } from "crypto";
     2→import type { Request, Response, NextFunction } from "express";
     3→
     4→const SESSION_COOKIE = "diplo_session";
     5→const SESSION_SECRET = process.env.SESSION_SECRET || "default-secret-change-me";
     6→
     7→function sign(value: string): string {
     8→  const hmac = createHmac("sha256", SESSION_SECRET);
     9→  hmac.update(value);
    10→  return `${value}.${hmac.digest("hex")}`;
    11→}
    12→
    13→function unsign(signed: string): string | false {
    14→  const lastDot = signed.lastIndexOf(".");
    15→  if (lastDot === -1) return false;
    16→  const value = signed.substring(0, lastDot);
    17→  const expected = sign(value);
    18→  try {
    19→    const signedBuf = Buffer.from(signed);
    20→    const expectedBuf = Buffer.from(expected);
    21→    if (signedBuf.length !== expectedBuf.length) return false;
    22→    if (timingSafeEqual(signedBuf, expectedBuf)) {
    23→      return value;
    24→    }
    25→  } catch {
    26→    return false;
    27→  }
    28→  return false;
    29→}
    30→
    31→export function createSession(res: Response): void {
    32→  const payload = `authenticated.${Date.now()}`;
    33→  const signed = sign(payload);
    34→  res.cookie(SESSION_COOKIE, signed, {
    35→    httpOnly: true,
    36→    secure: process.env.NODE_ENV === "production",
    37→    sameSite: "lax",
    38→    maxAge: 7 * 24 * 60 * 60 * 1000,
    39→  });
    40→}
    41→
    42→export function clearSession(res: Response): void {
    43→  res.clearCookie(SESSION_COOKIE);
    44→}
    45→
    46→export function requireAuth(req: Request, res: Response, next: NextFunction): void {
    47→  const cookie = req.cookies?.[SESSION_COOKIE];
    48→  if (!cookie) {
    49→    res.status(401).json({ error: "Unauthorized" });
    50→    return;
    51→  }
    52→  const result = unsign(cookie);
    53→  if (!result) {
    54→    res.status(401).json({ error: "Unauthorized" });
    55→    return;
    56→  }
    57→  next();
    58→}
    59→
    60→export function isAuthenticated(req: Request): boolean {
    61→  const cookie = req.cookies?.[SESSION_COOKIE];
    62→  if (!cookie) return false;
    63→  return unsign(cookie) !== false;
    64→}
