     8→export function fileToBase64(file: File): Promise<string> {
     9→  return new Promise((resolve, reject) => {
    10→    const reader = new FileReader();
    11→    reader.readAsDataURL(file);
    12→    reader.onload = () => {
    13→      if (typeof reader.result === "string") {
    14→        // Strip the data:image/...;base64, prefix
    15→        resolve(reader.result.split(",")[1]);
    16→      } else {
    17→        reject(new Error("Failed to convert file to base64"));
    18→      }
    19→    };
    20→    reader.onerror = (error) => reject(error);
    21→  });
    22→}
    23→
    24→export function createThumbnail(base64: string, mimeType: string, maxWidth = 300): Promise<string> {
    25→  return new Promise((resolve) => {
    26→    const img = new Image();
    27→    img.src = `data:${mimeType};base64,${base64}`;
    28→    img.onload = () => {
    29→      const canvas = document.createElement("canvas");
    30→      const ctx = canvas.getContext("2d");
    31→      if (!ctx) return resolve(base64); // Fallback to original if canvas fails
    32→      
    33→      const ratio = maxWidth / img.width;
    34→      const width = maxWidth;
    35→      const height = img.height * ratio;
    36→      
    37→      canvas.width = width;
    38→      canvas.height = height;
    39→      ctx.drawImage(img, 0, 0, width, height);
    40→      
    41→      const thumbDataUrl = canvas.toDataURL("image/jpeg", 0.7);
    42→      resolve(thumbDataUrl.split(",")[1]);
    43→    };
    44→    img.onerror = () => resolve(base64); // Fallback to original if load fails
    45→  });
    46→}
