import { drizzle } from "drizzle-orm/node-postgres";
import pg from "pg";
import * as schema from "./schema";

const { Pool } = pg;

if (!process.env.DATABASE_URL) {
  throw new Error(
    "DATABASE_URL must be set. Did you forget to provision a database?",
  );
}

export const pool = new Pool({ connectionString: process.env.DATABASE_URL });
export const db = drizzle(pool, { schema });

export * from "./schema";

export const DEFAULT_SETTINGS = [
  {
    platformId: "instagram",
    instructions: "Start with a visual hook referencing what the viewer sees. Use line breaks. Keep it engaging and punchy.",
    audience: "Global audience interested in geopolitics, maps, and world affairs. Ages 20–40.",
    language: "en",
  },
  {
    platformId: "facebook",
    instructions: "Write a clear, informative caption. Can include one analytical sentence. Slightly longer than Instagram is fine.",
    audience: "Broader general public, slightly older demographic. Interested in current events and history.",
    language: "en",
  },
  {
    platformId: "substack",
    instructions: "Write as a short 2–3 sentence intro paragraph for a newsletter post or note. Authoritative but not dry.",
    audience: "Subscribers who follow in-depth geopolitical and historical analysis. Educated, curious readers.",
    language: "en",
  },
  {
    platformId: "x",
    instructions: "Be punchy and direct. One strong statement or question. Maximum 280 characters.",
    audience: "Geopolitics enthusiasts, journalists, researchers, policy followers.",
    language: "en",
  },
  {
    platformId: "bluesky",
    instructions: "Thoughtful and direct. Similar to X but slightly more room for nuance. Max 300 characters.",
    audience: "Engaged, intellectually curious audience. Tech-forward, interested in global affairs.",
    language: "en",
  },
];

